package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        handleIncomingShare()
    }

    private fun handleIncomingShare() {
        val intent = intent
        val action = intent.action
        val type = intent.type

        when {
            Intent.ACTION_SEND == action && type != null -> {
                when {
                    type.startsWith("text/") -> handleSendText(intent)
                    type.startsWith("image/") -> handleSendImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE == action && type != null && type.startsWith("image/") -> {
                handleSendMultipleImages(intent)
            }
        }
    }

    private fun handleSendText(intent: Intent) {
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { sharedText ->
            // Process shared text
            Toast.makeText(this, "Shared Text: $sharedText", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSendImage(intent: Intent) {
        (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            // Process shared image
            Toast.makeText(this, "Shared Image URI: $imageUri", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSendMultipleImages(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris ->
            // Process shared images
            Toast.makeText(this, "Shared Multiple Images URIs: $imageUris", Toast.LENGTH_SHORT).show()
        }
    }
}